function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, Map<number, number>> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, new Map());
        }
        graph.get(u)!.set(v, cost);
    }

    // Use a priority queue to perform Dijkstra's algorithm
    // We prioritize paths with higher minimum edge cost
    const pq: [number, number, number][] = [];
    pq.push([0, 0, Infinity]); // [currentMinEdgeCost, currentTotalCost, currentNode]
    const visited: Set<number> = new Set();

    while (pq.length > 0) {
        // Sort the priority queue by currentMinEdgeCost in descending order
        pq.sort((a, b) => b[0] - a[0]);
        const [currentMin, currentTotal, node] = pq.shift()!;

        if (visited.has(node)) continue;
        visited.add(node);

        // If we reach the destination node, return the currentMin
        if (node === n - 1) {
            return currentMin;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const [neighbor, cost] of graph.get(node)!.entries()) {
                // Check if the neighbor is online
                if (!online[neighbor]) continue;

                // Calculate the new minimum edge cost and total cost
                const newMin = Math.min(currentMin, cost);
                const newTotal = currentTotal + cost;

                // If the new total cost is within k, add to the priority queue
                if (newTotal <= k) {
                    pq.push([newMin, newTotal, neighbor]);
                }
            }
        }
    }

    // If no valid path is found
    return -1;
}

