import "container/heap"

func solve(edges [][]int64, online []bool, k int64) int64 {
    n := len(online)
    graph := make(map[int64]map[int64]int64)

    // Build the graph
    for _, edge := range edges {
        u, v, cost := edge[0], edge[1], edge[2]
        if graph[u] == nil {
            graph[u] = make(map[int64]int64)
        }
        graph[u][v] = cost
    }

    // Define a priority queue element
    type PriorityQueueItem struct {
        currentMinEdgeCost int64
        currentTotalCost   int64
        node               int64
    }

    // Priority queue is a max-heap based on currentMinEdgeCost
    pq := make(PriorityQueue, 0)
    heap.Init(&pq)
    // Push the starting node with initial min edge cost as infinity and total cost as 0
    heap.Push(&pq, PriorityQueueItem{currentMinEdgeCost: 1<<63 - 1, currentTotalCost: 0, node: 0})

    // Visited set to avoid revisiting nodes
    visited := make(map[int64]bool)

    for pq.Len() > 0 {
        // Pop the element with the highest currentMinEdgeCost
        item := heap.Pop(&pq).(PriorityQueueItem)
        currentMinEdgeCost, currentTotalCost, node := item.currentMinEdgeCost, item.currentTotalCost, item.node

        // Skip if node is already visited
        if visited[node] {
            continue
        }
        visited[node] = true

        // If we reach the destination node, return the currentMinEdgeCost
        if node == int64(n-1) {
            return currentMinEdgeCost
        }

        // Explore neighbors
        if graph[node] != nil {
            for neighbor, cost := range graph[node] {
                // Check if the neighbor is online
                if !online[neighbor] {
                    continue
                }

                // Calculate the new minimum edge cost and total cost
                newMinEdgeCost := int64(math.Min(float64(currentMinEdgeCost), float64(cost)))
                newTotalCost := currentTotalCost + cost

                // If the new total cost is within k, add to the priority queue
                if newTotalCost <= k {
                    heap.Push(&pq, PriorityQueueItem{currentMinEdgeCost: newMinEdgeCost, currentTotalCost: newTotalCost, node: neighbor})
                }
            }
        }
    }

    // If no valid path is found
    return -1
}
